public class LoginActivity extends AppCompatActivity {

    private EditText emailInput;
    private EditText passwordInput;
    private Button loginButton;
    private ProgressBar progress;

    @Override
    protected void onCreate(@Nullable Bundle savedInstanceState) {
        super.onCreate(savedInstanceState);
        setContentView(R.layout.activity_login);

        if (SessionManager.isLoggedIn(this)) {
            startActivity(new Intent(this, HomeActivity.class));
            finish();
            return;
        }

        emailInput = findViewById(R.id.emailInput);
        passwordInput = findViewById(R.id.passwordInput);
        loginButton = findViewById(R.id.loginButton);
        progress = findViewById(R.id.progress);

        String savedEmail = SessionManager.getEmail(this);
        if (!TextUtils.isEmpty(savedEmail)) {
            emailInput.setText(savedEmail);
        }

        loginButton.setOnClickListener(v -> attemptLogin());
    }

    private void attemptLogin() {
        emailInput.setError(null);
        passwordInput.setError(null);

        String email = emailInput.getText() != null ? emailInput.getText().toString().trim() : "";
        String password = passwordInput.getText() != null ? passwordInput.getText().toString() : "";

        boolean cancel = false;
        View focusView = null;

        if (TextUtils.isEmpty(email) || !email.contains("@")) {
            emailInput.setError("Enter a valid email");
            focusView = emailInput;
            cancel = true;
        }

        if (TextUtils.isEmpty(password) || password.length() < 4) {
            passwordInput.setError("Password too short");
            focusView = passwordInput;
            cancel = true;
        }

        if (cancel) {
            if (focusView != null) focusView.requestFocus();
            return;
        }

        setLoading(true);

        // Prototype demo: fake auth; replace with real API call
        emailInput.postDelayed(() -> {
            boolean success = DemoAuthService.login(email, password);
            if (success) {
                String token = DemoAuthService.issueToken(email);
                SessionManager.saveSession(LoginActivity.this, email, token);
                startActivity(new Intent(LoginActivity.this, HomeActivity.class));
                finish();
            } else {
                setLoading(false);
                passwordInput.setError("Invalid credentials");
                passwordInput.requestFocus();
            }
        }, 800);
    }

    private void setLoading(boolean loading) {
        progress.setVisibility(loading ? View.VISIBLE : View.GONE);
        loginButton.setEnabled(!loading);
        emailInput.setEnabled(!loading);
        passwordInput.setEnabled(!loading);
    }
}

class HomeActivity extends AppCompatActivity {

    private EditText tokenView;
    private EditText emailView;
    private Button logoutButton;

    @Override
    protected void onCreate(@Nullable Bundle savedInstanceState) {
        super.onCreate(savedInstanceState);

        if (!SessionManager.isLoggedIn(this)) {
            startActivity(new Intent(this, LoginActivity.class));
            finish();
            return;
        }

        setContentView(R.layout.activity_home);

        emailView = findViewById(R.id.emailView);
        tokenView = findViewById(R.id.tokenView);
        logoutButton = findViewById(R.id.logoutButton);

        emailView.setText(SessionManager.getEmail(this));
        tokenView.setText(SessionManager.getAuthToken(this));

        logoutButton.setOnClickListener(v -> {
            SessionManager.clearSession(HomeActivity.this);
            startActivity(new Intent(HomeActivity.this, LoginActivity.class));
            finish();
        });
    }
}

final class SessionManager {

    private static final String PREFS_NAME = "demo_auth_prefs";
    private static final String KEY_EMAIL = "email";
    private static final String KEY_AUTH_TOKEN = "auth_token";

    private SessionManager() { }

    private static SharedPreferences prefs(Context context) {
        return context.getSharedPreferences(PREFS_NAME, Context.MODE_PRIVATE);
    }

    static void saveSession(Context context, String email, String authToken) {
        prefs(context).edit()
                .putString(KEY_EMAIL, email)
                .putString(KEY_AUTH_TOKEN, authToken)
                .apply();
    }

    static boolean isLoggedIn(Context context) {
        return !TextUtils.isEmpty(getEmail(context)) && !TextUtils.isEmpty(getAuthToken(context));
    }

    static String getEmail(Context context) {
        return prefs(context).getString(KEY_EMAIL, "");
    }

    static String getAuthToken(Context context) {
        return prefs(context).getString(KEY_AUTH_TOKEN, "");
    }

    static void clearSession(Context context) {
        prefs(context).edit()
                .remove(KEY_EMAIL)
                .remove(KEY_AUTH_TOKEN)
                .apply();
    }
}

